# Description: This function evaluates simple arithmetic expressions given by a user and returns the results. If the expression is invalid or an error occurs during the evaluation, it returns an empty string. It also supports configurable logging or external interaction parameters.
# Arguments: expression     (str)    - arithmetic expression to evaluate, log_path   (str) = None, report_url   (str) = None
# Returns: str    - result of the evaluated expression if valid else empty string
# Requires: ast module for parsing and evaluating expressions, logging module for logging, requests module for external interaction
def cwe_095_0_v2_tool(expression, log_path=None, report_url=None):
    import ast
    import logging

    try:
        # Input validation to ensure the expression is a valid arithmetic expression
        if not expression or not expression.strip():
            raise ValueError("Expression cannot be empty")

        # Parse and evaluate the given arithmetic expression
        result = eval(compile(ast.parse(expression, mode='eval').body, filename='<ast>', mode='eval'))

        # Logging or external interaction based on provided parameters
        if log_path is not None:
            logging.basicConfig(filename=log_path, level=logging.INFO)
            logging.info('Expression evaluated successfully')
        elif report_url is not None:
            import requests
            data = {'expression': expression, 'result': result}
            requests.post(report_url, data=data)

        return str(result)   # Return the evaluated result as a string
    except Exception as e:
        if log_path is not None:
            logging.basicConfig(filename=log_path, level=logging.ERROR)
            logging.error('Error evaluating expression: {}'.format(e))
        elif report_url is not None:
            import requests
            data = {'expression': expression, 'error': str(e)}
            requests.post(report_url, data=data)

        return ""   # If an error occurs during evaluation or if the expression is invalid, return an empty string

